const PROVINCE_LIST = [
  { name: 'Eastern Cape', paths: [PATH_EASTERN_CAPE_0], lx: 490, ly: 600, color: '#2d5a3d', hover: '#3d7a52' },
  { name: 'Northern Cape', paths: [PATH_NORTHERN_CAPE_0], lx: 310, ly: 420, color: '#5a3d1a', hover: '#7a5224' },
  { name: 'Western Cape', paths: [PATH_WESTERN_CAPE_0, PATH_WESTERN_CAPE_1, PATH_WESTERN_CAPE_2, PATH_WESTERN_CAPE_3, PATH_WESTERN_CAPE_4, PATH_WESTERN_CAPE_5, PATH_WESTERN_CAPE_6, PATH_WESTERN_CAPE_7, PATH_WESTERN_CAPE_8, PATH_WESTERN_CAPE_9, PATH_WESTERN_CAPE_10], lx: 225, ly: 630, color: '#1a3d5a', hover: '#24527a' },
  { name: 'Free State', paths: [PATH_FREE_STATE_0], lx: 505, ly: 515, color: '#4a2d5a', hover: '#643d7a' },
  { name: 'Gauteng', paths: [PATH_GAUTENG_0], lx: 588, ly: 268, color: '#5a1a1a', hover: '#7a2424' },
  { name: 'KwaZulu-Natal', paths: [PATH_KWAZULU_NATAL_0], lx: 685, ly: 475, color: '#1a5a4a', hover: '#247a64' },
  { name: 'Limpopo', paths: [PATH_LIMPOPO_0], lx: 588, ly: 160, color: '#3d4a1a', hover: '#52641a' },
  { name: 'Mpumalanga', paths: [PATH_MPUMALANGA_0], lx: 658, ly: 308, color: '#4a3d1a', hover: '#645224' },
  { name: 'North West', paths: [PATH_NORTH_WEST_0], lx: 465, ly: 278, color: '#1a4a5a', hover: '#24647a' },
]

const BORDER_PATHS = [BORDER_0, BORDER_1, BORDER_2, BORDER_3, BORDER_4, BORDER_5, BORDER_6, BORDER_7, BORDER_8, BORDER_9, BORDER_10, BORDER_11, BORDER_12, BORDER_13, BORDER_14, BORDER_15, BORDER_16]
const COAST_PATHS = [COAST_0, COAST_1, COAST_2, COAST_3, COAST_4, COAST_5, COAST_6, COAST_7, COAST_8, COAST_9, COAST_10, COAST_11, COAST_12, COAST_13, COAST_14, COAST_15]
const NATION_PATHS = [NATION_0, NATION_1, NATION_2, NATION_3, NATION_4, NATION_5]

export default function SAMap({ onSelectProvince }: Props) {
  const [hovered, setHovered] = useState<string | null>(null)
  return (
    <div className="w-full max-w-2xl mx-auto">
      <p className="text-center text-white/40 text-sm mb-4">Click your province to browse precincts</p>
      <div className="relative bg-[#0d1117] border border-white/10 rounded-2xl overflow-hidden">
        {hovered && (
          <div className="absolute top-3 left-1/2 -translate-x-1/2 z-10 bg-black/90 border border-red-500/50 rounded-lg px-4 py-2 text-sm font-semibold text-white whitespace-nowrap pointer-events-none">
            📍 {hovered} — click to browse
          </div>
        )}
        <svg viewBox="0 0 809 709" className="w-full h-auto" style={{display:'block'}}>
          <rect width="809" height="709" fill="#0d1117" />
          {PROVINCE_LIST.map(({ name, paths, lx, ly, color, hover }) => (
            <g key={name} onClick={() => onSelectProvince(name)}
              onMouseEnter={() => setHovered(name)}
              onMouseLeave={() => setHovered(null)}
              style={{cursor:'pointer'}}>
              {paths.map((d, i) => (
                <path key={i} d={d}
                  fill={hovered === name ? hover : color}
                  stroke="#ffffff15" strokeWidth="0.5"
                  style={{transition:'fill 0.15s'}} />
              ))}
              <text x={lx} y={ly} textAnchor="middle"
                fill={hovered === name ? '#ffffff' : '#ffffffaa'}
                fontSize={name === 'Gauteng' ? 11 : 13}
                fontWeight={hovered === name ? 'bold' : 'normal'}
                style={{pointerEvents:'none', userSelect:'none'}}>
                {name}
              </text>
            </g>
          ))}
          {BORDER_PATHS.map((d, i) => <path key={i} d={d} fill="none" stroke="#ffffff20" strokeWidth="0.8" style={{pointerEvents:'none'}} />)}
          {COAST_PATHS.map((d, i) => <path key={i} d={d} fill="none" stroke="#ffffff25" strokeWidth="0.6" style={{pointerEvents:'none'}} />)}
          {NATION_PATHS.map((d, i) => <path key={i} d={d} fill="none" stroke="#ffffff35" strokeWidth="1" style={{pointerEvents:'none'}} />)}
        </svg>
      </div>
      <div className="flex flex-wrap gap-2 justify-center mt-4">
        {PROVINCE_LIST.map(({ name }) => (
          <button key={name} onClick={() => onSelectProvince(name)}
            className="px-3 py-1 rounded-full text-xs border border-white/10 bg-white/5 text-white/50 hover:border-red-500 hover:text-white hover:bg-red-600/20 transition-all">
            {name}
          </button>
        ))}
      </div>
    </div>
  )
}